import type {SidebarsConfig} from '@docusaurus/plugin-content-docs';

/**
 * Sidebar configuration for the Control Plane documentation.
 *
 * Uses autogenerated sidebars based on the filesystem structure.
 * Each top-level directory in docs/docs/ becomes a category.
 * Use _category_.json files within directories to control ordering and labels.
 *
 * @see https://docusaurus.io/docs/sidebar
 */
const sidebars: SidebarsConfig = {
  docsSidebar: [{type: 'autogenerated', dirName: '.'}],
};

export default sidebars;
